  1	import * as React from 'react';
  2	import ResourceDropdown from '@odf/shared/dropdown/ResourceDropdown';
  3	import { FormGroupController } from '@odf/shared/form-group-controller';
  4	import { SecretModel } from '@odf/shared/models';
  5	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  6	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
  7	import classNames from 'classnames';
  8	import * as _ from 'lodash-es';
  9	import { Control } from 'react-hook-form';
 10	import {
 11	  Button,
 12	  FormGroup,
 13	  TextInput,
 14	  InputGroup,
 15	  TextArea,
 16	  PopoverPosition,
 17	  Popover,
 18	  InputGroupItem,
 19	  FormHelperText,
 20	  HelperText,
 21	  HelperTextItem,
 22	} from '@patternfly/react-core';
 23	import { HelpIcon } from '@patternfly/react-icons';
 24	import {
 25	  BackingStoreAction,
 26	  BackingStoreProviderDataState,
 27	} from '../create-bs/reducer';
 28	import './noobaa-provider-endpoints.scss';
 29	
 30	type GCPEndPointTypeProps = {
 31	  state: BackingStoreProviderDataState;
 32	  dispatch: React.Dispatch<BackingStoreAction>;
 33	  namespace: string;
 34	  control: Control;
 35	};
 36	
 37	type ExternalLinkProps = {
 38	  href: string;
 39	  text?: React.ReactNode;
 40	  additionalClassName?: string;
 41	  dataTestID?: string;
 42	  stopPropagation?: boolean;
 43	};
 44	
 45	export const ExternalLink: React.FC<ExternalLinkProps> = ({
 46	  children,
 47	  href,
 48	  text,
 49	  additionalClassName = '',
 50	  dataTestID,
 51	  stopPropagation,
 52	}) => (
 53	  <a
 54	    className={classNames('co-external-link', additionalClassName)}
 55	    href={href}
 56	    target="_blank"
 57	    rel="noopener noreferrer"
 58	    data-test-id={dataTestID}
 59	    {...(stopPropagation ? { onClick: (e) => e.stopPropagation() } : {})}
 60	  >
 61	    {children || text}
 62	  </a>
 63	);
 64	
 65	export const GCPEndpointType: React.FC<GCPEndPointTypeProps> = (props) => {
 66	  const { t } = useCustomTranslation();
 67	
 68	  const [fileData, setFileData] = React.useState('');
 69	  const [showSecret, setShowSecret] = React.useState(false);
 70	  const { dispatch, namespace, control } = props;
 71	
 72	  const toggleShowSecret = () => setShowSecret((isShown) => !isShown);
 73	
 74	  const gcpHelpText = (
 75	    <Popover
 76	      position={PopoverPosition.top}
 77	      headerContent=" "
 78	      bodyContent={
 79	        <div>
 80	          {t(
 81	            'Service account keys are needed for Google Cloud Storage authentication. The keys can be found in the service accounts page in the GCP console.'
 82	          )}
 83	          <ExternalLink
 84	            href="https://cloud.google.com/iam/docs/service-accounts#service_account_keys"
 85	            text={t('Learn more')}
 86	          />
 87	        </div>
 88	      }
 89	      enableFlip
 90	      maxWidth="21rem"
 91	    >
 92	      <Button variant="link">
 93	        <HelpIcon />
 94	        {t('Where can I find Google Cloud credentials?')}
 95	      </Button>
 96	    </Popover>
 97	  );
 98	
 99	  const onUpload = (event, setInputData) => {
100	    event.preventDefault();
101	    const file = event.target.files[0];
102	    const reader = new FileReader();
103	    reader.onload = (ev) => {
104	      const data = _.get(ev, 'target.result') as string;
105	      setFileData(data);
106	      setInputData(file.name);
107	      dispatch({ type: 'setGcpJSON', value: data });
108	    };
109	    reader.readAsText(file);
110	  };
111	
112	  return (
113	    <>
114	      <FormGroupController
115	        name="secret-key"
116	        control={control}
117	        formGroupProps={{
118	          className: 'nb-endpoints-form-entry',
119	          helperText: !showSecret
120	            ? t(
121	                'Upload a .json file with the service account keys provided by Google Cloud Storage.'
122	              )
123	            : null,
124	          label: t('Secret Key'),
125	          fieldId: 'secret-key',
126	          isRequired: true,
127	        }}
128	        render={({ value, onChange, onBlur }) =>
129	          !showSecret ? (
130	            <InputGroup>
131	              <InputGroupItem isFill>
132	                <TextInput
133	                  readOnly
134	                  value={value}
135	                  className="nb-endpoints-form-entry__file-name"
136	                  placeholder={t('Upload JSON')}
137	                  aria-label={t('Uploaded File Name')}
138	                />
139	              </InputGroupItem>
140	              <InputGroupItem>
141	                <div className="inputbtn nb-endpoints-form-entry-upload-btn">
142	                  <Button
143	                    href="#"
144	                    variant="secondary"
145	                    className="custom-input-btn nb-endpoints-form-entry-upload-btn__button"
146	                    aria-label={t('Upload File')}
147	                  >
148	                    {t('Browse')}
149	                  </Button>
150	                  <input
151	                    type="file"
152	                    id="inputButton"
153	                    className="nb-endpoints-form-entry-upload-btn__input"
154	                    onChange={(ev) => onUpload(ev, onChange)}
155	                    onBlur={onBlur}
156	                    aria-label={t('Upload File')}
157	                  />
158	                </div>
159	              </InputGroupItem>
160	              <InputGroupItem>
161	                <Button
162	                  variant="plain"
163	                  onClick={toggleShowSecret}
164	                  aria-label={t('Switch to Secret')}
165	                >
166	                  {t('Switch to Secret')}
167	                </Button>
168	              </InputGroupItem>
169	            </InputGroup>
170	          ) : (
171	            <InputGroup>
172	              <InputGroupItem>
173	                <ResourceDropdown<K8sResourceCommon>
174	                  className="nb-endpoints-form-entry__dropdown nb-endpoints-form-entry__dropdown--full-width"
175	                  onSelect={(e) => {
176	                    onChange(e.metadata.name);
177	                    dispatch({ type: 'setSecretName', value: e.metadata.name });
178	                  }}
179	                  resourceModel={SecretModel}
180	                  resource={{
181	                    namespace,
182	                    kind: SecretModel.kind,
183	                    isList: true,
184	                  }}
185	                />
186	              </InputGroupItem>
187	              <InputGroupItem>
188	                <Button
189	                  variant="plain"
190	                  onClick={toggleShowSecret}
191	                  aria-label={t('Switch to upload JSON')}
192	                >
193	                  {t('Switch to upload JSON')}
194	                </Button>
195	              </InputGroupItem>
196	            </InputGroup>
197	          )
198	        }
199	      />
200	      {!showSecret && (
201	        <FormGroup className="nb-endpoints-form-entry" fieldId="gcp-data">
202	          <TextArea
203	            aria-label={t('Cluster Metadata')}
204	            className="nb-endpoints-form-entry__data-dump"
205	            value={fileData}
206	          />
207	          <FormHelperText>
208	            <HelperText>
209	              <HelperTextItem>{gcpHelpText}</HelperTextItem>
210	            </HelperText>
211	          </FormHelperText>
212	        </FormGroup>
213	      )}
214	      <FormGroupController
215	        name="target-bucket"
216	        control={control}
217	        formGroupProps={{
218	          className: 'nb-endpoints-form-entry',
219	          label: t('Target Bucket'),
220	          fieldId: 'target-bucket',
221	          isRequired: true,
222	        }}
223	        render={({ value, onChange, onBlur }) => (
224	          <TextInput
225	            value={value}
226	            onChange={(_event, val) => {
227	              onChange(val);
228	              dispatch({ type: 'setTarget', value: val });
229	            }}
230	            onBlur={onBlur}
231	            aria-label={t('Target Bucket')}
232	          />
233	        )}
234	      />
235	    </>
236	  );
237	};

