 65	export const GCPEndpointType: React.FC<GCPEndPointTypeProps> = (props) => {
 66	  const { t } = useCustomTranslation();
 67	
 68	  const [fileData, setFileData] = React.useState('');
 69	  const [showSecret, setShowSecret] = React.useState(false);
 70	  const { dispatch, namespace, control } = props;
 71	
 72	  const toggleShowSecret = () => setShowSecret((isShown) => !isShown);
 73	
 74	  const gcpHelpText = (
 75	    <Popover
 76	      position={PopoverPosition.top}
 77	      headerContent=" "
 78	      bodyContent={
 79	        <div>
 80	          {t(
 81	            'Service account keys are needed for Google Cloud Storage authentication. The keys can be found in the service accounts page in the GCP console.'
 82	          )}
 83	          <ExternalLink
 84	            href="https://cloud.google.com/iam/docs/service-accounts#service_account_keys"
 85	            text={t('Learn more')}
 86	          />
 87	        </div>
 88	      }
 89	      enableFlip
 90	      maxWidth="21rem"
 91	    >
 92	      <Button variant="link" icon={<HelpIcon />}>
 93	        {t('Where can I find Google Cloud credentials?')}
 94	      </Button>
 95	    </Popover>
 96	  );
 97	
 98	  const onUpload = (event, setInputData) => {
 99	    event.preventDefault();
100	    const file = event.target.files[0];
101	    const reader = new FileReader();
102	    reader.onload = (ev) => {
103	      const data = _.get(ev, 'target.result') as string;
104	      setFileData(data);
105	      setInputData(file.name);
106	      dispatch({ type: 'setGcpJSON', value: data });
107	    };
108	    reader.readAsText(file);
109	  };
110	
111	  return (
112	    <>
113	      <FormGroupController
114	        name="secret-key"
115	        control={control}
116	        formGroupProps={{
117	          className: 'nb-endpoints-form-entry',
118	          helperText: !showSecret
119	            ? t(
120	                'Upload a .json file with the service account keys provided by Google Cloud Storage.'
121	              )
122	            : null,
123	          label: t('Secret Key'),
124	          fieldId: 'secret-key',
125	          isRequired: true,
126	        }}
127	        render={({ value, onChange, onBlur }) =>
128	          !showSecret ? (
129	            <InputGroup>
130	              <InputGroupItem isFill>
131	                <TextInput
132	                  readOnly
133	                  value={value}
134	                  className="nb-endpoints-form-entry__file-name"
135	                  placeholder={t('Upload JSON')}
136	                  aria-label={t('Uploaded File Name')}
137	                />
138	              </InputGroupItem>
139	              <InputGroupItem>
140	                <div className="inputbtn nb-endpoints-form-entry-upload-btn">
141	                  <Button
142	                    href="#"
143	                    variant="secondary"
144	                    className="custom-input-btn nb-endpoints-form-entry-upload-btn__button"
145	                    aria-label={t('Upload File')}
146	                  >
147	                    {t('Browse')}
148	                  </Button>
149	                  <input
150	                    type="file"
151	                    id="inputButton"
152	                    className="nb-endpoints-form-entry-upload-btn__input"
153	                    onChange={(ev) => onUpload(ev, onChange)}
154	                    onBlur={onBlur}
155	                    aria-label={t('Upload File')}
156	                  />
157	                </div>
158	              </InputGroupItem>
159	              <InputGroupItem>
160	                <Button
161	                  variant="plain"
162	                  onClick={toggleShowSecret}
163	                  aria-label={t('Switch to Secret')}
164	                >
165	                  {t('Switch to Secret')}
166	                </Button>
167	              </InputGroupItem>
168	            </InputGroup>
169	          ) : (
170	            <InputGroup>
171	              <InputGroupItem>
172	                <ResourceDropdown<K8sResourceCommon>
173	                  className="nb-endpoints-form-entry__dropdown nb-endpoints-form-entry__dropdown--full-width"
174	                  onSelect={(e) => {
175	                    onChange(e.metadata.name);
176	                    dispatch({ type: 'setSecretName', value: e.metadata.name });
177	                  }}
178	                  resourceModel={SecretModel}
179	                  resource={{
180	                    namespace,
181	                    kind: SecretModel.kind,
182	                    isList: true,
183	                  }}
184	                />
185	              </InputGroupItem>
186	              <InputGroupItem>
187	                <Button
188	                  variant="plain"
189	                  onClick={toggleShowSecret}
190	                  aria-label={t('Switch to upload JSON')}
191	                >
192	                  {t('Switch to upload JSON')}
193	                </Button>
194	              </InputGroupItem>
195	            </InputGroup>
196	          )
197	        }
198	      />
199	      {!showSecret && (
200	        <FormGroup className="nb-endpoints-form-entry" fieldId="gcp-data">
201	          <TextArea
202	            aria-label={t('Cluster Metadata')}
203	            className="nb-endpoints-form-entry__data-dump"
204	            value={fileData}
205	          />
206	          <FormHelperText>
207	            <HelperText>
208	              <HelperTextItem>{gcpHelpText}</HelperTextItem>
209	            </HelperText>
210	          </FormHelperText>
211	        </FormGroup>
212	      )}
213	      <FormGroupController
214	        name="target-bucket"
215	        control={control}
216	        formGroupProps={{
217	          className: 'nb-endpoints-form-entry',
218	          label: t('Target Bucket'),
219	          fieldId: 'target-bucket',
220	          isRequired: true,
221	        }}
222	        render={({ value, onChange, onBlur }) => (
223	          <TextInput
224	            value={value}
225	            onChange={(_event, val) => {
226	              onChange(val);
227	              dispatch({ type: 'setTarget', value: val });
228	            }}
229	            onBlur={onBlur}
230	            aria-label={t('Target Bucket')}
231	          />
232	        )}
233	      />
234	    </>
235	  );
236	};
